import React, { useState, useEffect } from "react";
import api from "../api/api";

export default function Dashboard() {
  const [resumen, setResumen] = useState({
    totalProductos: 0,
    totalCategorias: 0,
    totalClientes: 0,
    ventasHoy: 0
  });

  const nombreUsuario = localStorage.getItem("nombre") || "Administrador";

  useEffect(() => {
    obtenerEstadisticas();
  }, []);

  const obtenerEstadisticas = async () => {
    try {
      // Intentamos traer datos reales de tu MongoDB Atlas
      const [prod, cat, cli] = await Promise.all([
        api.get("/productos"),
        api.get("/categorias"),
        api.get("/clientes")
      ]);
      
      setResumen({
        totalProductos: prod.data.length,
        totalCategorias: cat.data.length,
        totalClientes: cli.data.length,
        ventasHoy: 0 
      });
    } catch (error) {
      console.error("Error al cargar estadísticas:", error);
    }
  };

  return (
    <div className="container-fluid">
      <div className="mb-4">
        <h2 className="fw-bold text-dark">Panel de Control</h2>
        <p className="text-muted">¡Hola de nuevo, {nombreUsuario}! Este es el resumen de tu sistema hoy.</p>
      </div>

      <div className="row g-4">
        {/* Productos */}
        <div className="col-md-3">
          <div className="card border-0 shadow-sm p-3" style={{ borderLeft: "5px solid #0d6efd", borderRadius: "12px" }}>
            <div className="d-flex align-items-center">
              <div className="bg-primary bg-opacity-10 p-3 rounded-circle me-3">
                <span>📦</span>
              </div>
              <div>
                <h6 className="text-muted mb-1 small">Productos</h6>
                <h4 className="fw-bold mb-0">{resumen.totalProductos}</h4>
              </div>
            </div>
          </div>
        </div>

        {/* Categorías */}
        <div className="col-md-3">
          <div className="card border-0 shadow-sm p-3" style={{ borderLeft: "5px solid #198754", borderRadius: "12px" }}>
            <div className="d-flex align-items-center">
              <div className="bg-success bg-opacity-10 p-3 rounded-circle me-3">
                <span>📁</span>
              </div>
              <div>
                <h6 className="text-muted mb-1 small">Categorías</h6>
                <h4 className="fw-bold mb-0">{resumen.totalCategorias}</h4>
              </div>
            </div>
          </div>
        </div>

       

        {/* Ventas */}
        <div className="col-md-3">
          <div className="card border-0 shadow-sm p-3" style={{ borderLeft: "5px solid #dc3545", borderRadius: "12px" }}>
            <div className="d-flex align-items-center">
              <div className="bg-danger bg-opacity-10 p-3 rounded-circle me-3">
                <span>💰</span>
              </div>
              <div>
                <h6 className="text-muted mb-1 small">Ventas Hoy</h6>
                <h4 className="fw-bold mb-0">${resumen.ventasHoy.toFixed(2)}</h4>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="row mt-5">
        <div className="col-md-12">
          <div className="card border-0 shadow-sm p-4" style={{ borderRadius: "15px" }}>
            <h5 className="fw-bold mb-4">Acciones Rápidas</h5>
            <div className="d-flex gap-3">
              <button className="btn btn-primary px-4 py-2 shadow-sm" onClick={() => window.location.href='/ventas'}>
                + Nueva Venta
              </button>
              <button className="btn btn-outline-secondary px-4 py-2" onClick={() => window.location.href='/productos'}>
                Ver Inventario
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
